const markGatewayOutboundDelivered = `-- name: MarkGatewayOutboundDelivered :one
update messages
set metadata = metadata || jsonb_build_object(
  'gateway_delivered_at', coalesce(metadata->'gateway_delivered_at', to_jsonb($1::timestamptz))
),
updated_at = $1
where id = $2::uuid
  and sender_type = 'agent'
  and deleted_at is null
returning id::text, metadata
`

