const updateAgentVisibility = `-- name: UpdateAgentVisibility :one

with prior as (
  select id, visibility as old_visibility, workspace_id, name, slug
  from agents
  where id = $3::uuid
    and deleted_at is null
)
update agents
set visibility = $1,
    updated_at = $2
from prior
where agents.id = prior.id
returning
  agents.id::text,
  agents.workspace_id::text,
  agents.name,
  agents.slug,
  prior.old_visibility,
  agents.visibility as new_visibility,
  agents.updated_at
`

