const upsertConversationInflightTerminalDelivered = `-- name: UpsertConversationInflightTerminalDelivered :exec
update conversations
set metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object(
      'gateway_inflight',
      coalesce(metadata->'gateway_inflight', '{}'::jsonb) || jsonb_build_object(
        'terminal_delivered',
        (coalesce(metadata->'gateway_inflight'->'terminal_delivered', '{}'::jsonb)
          - 'run_id')
        || jsonb_build_object(
          'run_ids',
          (coalesce(metadata->'gateway_inflight'->'terminal_delivered'->'run_ids', '[]'::jsonb)
            - $1::text)
          || jsonb_build_array($1::text),
          'delivered_at', to_jsonb($2::timestamptz)
        )
      )
    ),
    updated_at = $2
where id = $3::uuid
  and deleted_at is null
`

type UpsertConversationInflightTerminalDeliveredParams struct {
	RunID          string             `json:"run_id"`
	Now            pgtype.Timestamptz `json:"now"`
	ConversationID pgtype.UUID        `json:"conversation_id"`
}

// Append run_id to gateway_inflight.terminal_delivered.run_ids
// (jsonb set; `- @run_id || array[@run_id]` keeps it deduped). Wipes
// the legacy single-value `run_id` field — reads still accept it via
// an OR, so the migration is lazy across a rolling deploy.
func (q *Queries) UpsertConversationInflightTerminalDelivered(ctx context.Context, arg UpsertConversationInflightTerminalDeliveredParams) error {
	_, err := q.db.Exec(ctx, upsertConversationInflightTerminalDelivered, arg.RunID, arg.Now, arg.ConversationID)
	return err
}

