const upsertEmailPasswordIdentity = `-- name: UpsertEmailPasswordIdentity :exec

insert into auth_identities(id, user_id, provider, subject, metadata, created_at, updated_at)
values ($1::uuid, $2::uuid, 'email', $3, $4::jsonb, $5, $5)
on conflict (provider, subject) do update
set user_id    = excluded.user_id,
    metadata   = excluded.metadata,
    updated_at = excluded.updated_at
`

type UpsertEmailPasswordIdentityParams struct {
	ID       pgtype.UUID        `json:"id"`
	UserID   pgtype.UUID        `json:"user_id"`
	Email    string             `json:"email"`
	Metadata []byte             `json:"metadata"`
	Now      pgtype.Timestamptz `json:"now"`
}

// ============================================================
// Email/password identity (local email+password login)
// ============================================================
//
// provider='email' is the canonical local password identity. subject
// stores the email (mirrors users.email); metadata stores the bcrypt
// hash. Uniqueness on (provider, subject) is already enforced by
// uk_auth_identities_provider_subject in 000001.
//
// Password strength validation lives in the password package at the
// handler layer. SQL only persists and reads.
// Called on first-time registration or password change. Caller
// assembles the metadata blob { "password_hash": ..., "hashed_at": ... }
// so this file needs no jsonb_build_object gymnastics.
func (q *Queries) UpsertEmailPasswordIdentity(ctx context.Context, arg UpsertEmailPasswordIdentityParams) error {
	_, err := q.db.Exec(ctx, upsertEmailPasswordIdentity,
		arg.ID,
		arg.UserID,
		arg.Email,
		arg.Metadata,
		arg.Now,
	)
	return err
}

const upsertUserByEmail = `-- name: UpsertUserByEmail :one
with inserted as (
  insert into users(id, email, name, status, created_at, updated_at)
  select $1::uuid, $2, $3, 'active', $4, $4
  where not exists (
    select 1 from users
    where users.email = $2 and users.deleted_at is null
  )
  returning users.id, users.email, users.name, users.status, users.created_at, users.updated_at
)
select
  i.id::text as id,
  i.email,
  i.name,
  i.status,
  i.created_at,
  i.updated_at,
  true as created
from inserted i
union all
select
  u.id::text as id,
  u.email,
  u.name,
  u.status,
  u.created_at,
  u.updated_at,
  false as created
from users u
where u.email = $2
  and u.deleted_at is null
  and not exists (select 1 from inserted)
limit 1
`

type UpsertUserByEmailParams struct {
	ID    pgtype.UUID        `json:"id"`
	Email string             `json:"email"`
	Name  string             `json:"name"`
	Now   pgtype.Timestamptz `json:"now"`
}

type UpsertUserByEmailRow struct {
	ID        string             `json:"id"`
	Email     string             `json:"email"`
	Name      string             `json:"name"`
	Status    string             `json:"status"`
	CreatedAt pgtype.Timestamptz `json:"created_at"`
	UpdatedAt pgtype.Timestamptz `json:"updated_at"`
	Created   bool               `json:"created"`
}

// Idempotent user upsert by email. If a non-deleted user already exists
// with this email, returns that user's id (status / name untouched).
// Otherwise inserts a fresh user row and returns the new id. `created`
// tells the caller whether they're looking at a fresh row or a pre-
// existing one.
func (q *Queries) UpsertUserByEmail(ctx context.Context, arg UpsertUserByEmailParams) (UpsertUserByEmailRow, error) {
	row := q.db.QueryRow(ctx, upsertUserByEmail,
		arg.ID,
		arg.Email,
		arg.Name,
		arg.Now,
	)
	var i UpsertUserByEmailRow
	err := row.Scan(
		&i.ID,
		&i.Email,
		&i.Name,
		&i.Status,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.Created,
	)
	return i, err
}

